mapper.insert:
        INSERT INTO MBA.TB_MBA_TICKET_CURRENT
        (
              TICKET_ID, CLUSTER_NO, TICKET_TYPE, TICKET_GENERATION_TIME, FAULT_TIME
            , ROOT_CAUSE_TYPE, ROOT_CAUSE_CODE, ROOT_CAUSE_DOMAIN, TOTAL_RELATED_ALARM_CNT, STATUS
            , TICKET_RCA_RESULT_CODE, TICKET_RCA_RESULT_DTL_CODE, TICKET_RCA_RESULT_ORIG_DTL_CODE, PARENT_TICKET_ID, OCCUR
            , DIRECTION, TRUNK_ID, TRUNK_NAME
        )
        VALUES
        (
              #{ticketId}, #{clusterNo}, #{ticketType}, (SELECT NOW()), #{faultTime}
--             , #{rootCauseType}, #{rootCauseCode}, #{rootCauseDomain}, #{relatedAlarmCnt}, #{status}
            , #{rootCauseType}, #{rootCauseCode}, #{rootCauseDomain}, #{totalRelatedAlarmCnt}, #{status}
            , #{ticketRcaResultCode}, #{ticketRcaResultDtlCode}, #{ticketRcaResultDtlCode}, #{parentTicketId}, #{occur}
            , #{direction}, #{trunkId}, #{trunkName}
        )

